export const RAJA_AMPAT_SITES: DiveSite[] = [
  // ── DAMPIER STRAIT — CORE SITES ────────────────────────────────────────
  { slug:'cape-kri',name:'Cape Kri',area:'Dampier Strait',areaSlug:'dampier-strait',rank:1,type:'Reef',access:'Boat',minDepth:5,maxDepth:38,avgDepth:22,visibility:'15–30m',temp:'27–30°C',current:'Mild to strong — tide-dependent',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Dawn and dusk year-round — best Oct–Apr',bestSeason:'Oct–Apr',goodFor:['Pelagics','Big fish','World record marine biodiversity','Reef diving','Photography'],facilities:['Sorido Bay Resort','Kri Eco Resort','Papua Diving Resorts','Kri Island homestays'],lat:-0.5526,lng:130.6806,rating:5.0,reviews:312,description:'THE signature dive of Raja Ampat. This eastern tip of Mansuar is where currents from two directions converge, creating a superhighway for marine life. WORLD RECORD: 374 fish species recorded on a single dive by Dr. Gerry Allen (2012) — the highest fish count ever recorded on a single dive. Dense schools of fusiliers, jacks, sweetlips, barracuda, surgeonfish. Pelagics: blacktip and grey reef sharks, giant trevally, Spanish mackerel, dogtooth tuna, Napoleon wrasse, bumphead parrotfish at dawn, occasional oceanic mantas. Macro: pygmy seahorses, nudibranchs, wobbegong sharks under overhangs. Reef-hook dive on running current — hook in and watch the show.',marineLife:[{name:'Schooling fusiliers',frequency:'very common'},{name:'Giant trevally',frequency:'very common'},{name:'Grey reef shark',frequency:'common'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Pygmy seahorse',frequency:'common'}],safetyNotes:['One of the most current-dependent sites in Raja Ampat — tide timing critical','Reef hook required on strong current days','Keep eye on blue for unexpected pelagic encounters','New divers may be overwhelmed by sheer volume of life'],briefing:'Boat drop at eastern ridge of Mansuar — entry point varies by tide: north corner, south corner, or saddle drift. Negative entry may be used on strong current days. Hook into corner and watch the show. Ascend at shallower saddle or reef edge for safety stop. SMB for surface pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'blue-magic',name:'Blue Magic',area:'Dampier Strait',areaSlug:'dampier-strait',rank:2,type:'Reef',access:'Boat',minDepth:8,maxDepth:30,avgDepth:20,visibility:'15–30m',temp:'27–30°C',current:'Mild to very strong — tide-dependent',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Nov–Apr for oceanic mantas',bestSeason:'Nov–Apr',goodFor:['Oceanic manta rays','Pelagics','Big fish','Seamount diving'],facilities:['Sorido Bay Resort','Kri Eco Resort','Kri/Mansuar homestays'],lat:-0.557,lng:130.678,rating:4.9,reviews:267,description:'A submerged seamount between Mansuar and Cape Kri that acts as a magnet for everything in the Dampier Strait. The seamount top sits at ~8m, dropping to 30m+. OCEANIC MANTAS (Mobula birostris) regularly pass Nov–Apr, sometimes in large numbers. Schools of barracuda in spiral formations, rainbow runners, bluefin jacks, grey and blacktip reef sharks, giant trevally cutting through schooling batfish. The most condition-dependent site in Raja Ampat — same site can be a serene drift or a reef-hook battle. Negative entry technique required. When it works, most guests rate it as their favourite dive.',marineLife:[{name:'Oceanic manta ray',frequency:'seasonal (Nov–Apr)'},{name:'Grey reef shark',frequency:'common'},{name:'Schooling barracuda',frequency:'very common'},{name:'Rainbow runner',frequency:'common'},{name:'Giant trevally',frequency:'common'}],safetyNotes:['Negative entry required — seamount in open water with no visual reference for descent','Reef hooks essential on strong current days','Advanced certification strongly recommended','Same site completely different on different tides'],briefing:'Boat drop at exposed seamount. Fast negative entry — drop to top of mount at ~8m immediately. Hook in if current running. Mantas appear from the blue — stay calm and still. On slack: drift along reef sides. Drift off seamount for ascent. SMB for surface pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'sardine-reef',name:'Sardine Reef',area:'Dampier Strait',areaSlug:'dampier-strait',rank:3,type:'Reef',access:'Boat',minDepth:5,maxDepth:30,avgDepth:16,visibility:'15–30m',temp:'27–30°C',current:'Mild to moderate — usually drift-friendly',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Schooling fish','Pelagics','Reef diving','Photography','All levels'],facilities:['Sorido Bay Resort','Kri Eco Resort','Kri Island homestays'],lat:-0.543,lng:130.695,rating:4.8,reviews:198,description:'Named by Max Ammer who described his first dive as being packed inside a can of sardines. This oval-shaped submerged ridge rises from 30m to 5m, with fusiliers and other schooling fish swirling in tornado formations when predators close in. Grey reef sharks circle the deeper edge. Wobbegong and epaulette (walking) sharks rest under coral plates in the shallows. Giant trevally, dogtooth tuna, and Spanish mackerel hunt the bait balls. More accessible than Cape Kri — excellent for newer divers who want the full Raja Ampat experience without technical demands.',marineLife:[{name:'Schooling fusiliers',frequency:'very common'},{name:'Grey reef shark',frequency:'common'},{name:'Wobbegong shark',frequency:'common'},{name:'Giant trevally',frequency:'common'},{name:'Pygmy seahorse',frequency:'occasional'}],safetyNotes:['Drift dive — stay with guide and buddy','SMB mandatory for boat pickup','Monitor depth on deeper reef edge'],briefing:'Boat drop on the oval ridge. Drift entry along the reef. Fusiliers form tornado formations around you. Keep eye on blue for hunting trevally and sharks. Ascend from shallower reef section at 5m. SMB for pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'manta-sandy',name:'Manta Sandy',area:'Dampier Strait',areaSlug:'dampier-strait',rank:4,type:'Reef',access:'Boat',minDepth:10,maxDepth:15,avgDepth:12,visibility:'15–25m',temp:'27–30°C',current:'None to mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Dec–Mar peak — Oct–Apr reliable',bestSeason:'Oct–Apr',goodFor:['Reef manta rays','Beginners','Snorkelling','Photography','Marine life'],facilities:['Arborek Island homestays','Mansuar resorts','Liveaboards'],lat:-0.574,lng:130.536,rating:4.8,reviews:234,description:'A shallow sandy plateau between Mansuar and Arborek that is Raja Ampat\'s most reliable and accessible manta cleaning station. Reef mantas (Mobula alfredi) pause to be cleaned by wrasses and angelfish. When active, 5–6 mantas may be in the water simultaneously, sometimes passing within metres. Divers kneel along the viewing line on the sand — patience is essential. Most week-long trips include 3–4 attempts; most divers see mantas on at least two. Also excellent for snorkellers.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Schooling fusiliers',frequency:'common'}],safetyNotes:['Strict manta etiquette: no chasing, no kicking up sand, no positioning above cleaning station','Some dives produce zero mantas — patience required','No touching the sandy bottom near the cleaning station'],briefing:'Anchor near buoy line. Descend to sandy bottom at 10–15m and kneel along the viewing line. Stay still and low. Mantas will circle in from the blue to the cleaning station. Do not chase or swim above them. Ascend slowly after guide signal. SMB pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'manta-ridge',name:'Manta Ridge',area:'Dampier Strait',areaSlug:'dampier-strait',rank:5,type:'Reef',access:'Boat',minDepth:6,maxDepth:25,avgDepth:14,visibility:'15–25m',temp:'27–30°C',current:'Mild to strong',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Nov–Apr manta season',bestSeason:'Nov–Apr',goodFor:['Reef manta rays','Oceanic manta rays','Photography','Marine life'],facilities:['Arborek homestays','Mansuar/Kri resorts'],lat:-0.568,lng:130.541,rating:4.9,reviews:287,description:'Perhaps the most reliable manta cleaning station in Raja Ampat\'s MPA. Both reef mantas (Mobula alfredi) and oceanic mantas (Mobula birostris) visit this ridge, especially Nov–Apr. Divers reef-hook onto the ridge and watch groups of 5–30 manta rays circle to be cleaned of parasites by butterflyfish and wrasses. The experience of watching these graceful giants glide just metres away is one of Raja Ampat\'s most iconic. Schools of fusiliers and jacks swept in by current.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Oceanic manta ray',frequency:'seasonal (Nov–Apr)'},{name:'Schooling jacks',frequency:'common'},{name:'Blacktip reef shark',frequency:'occasional'}],safetyNotes:['Reef hook dive — good buoyancy control essential','WARNING: Avoid southern slope — dangerous down-currents especially during ascent','No chasing or crowding mantas'],briefing:'Boat drop at ridge top. Descend and hook onto reef — keep reef on right, swim west along the ridge. Hook in and wait. Mantas arrive from current direction and circle the cleaning station. Head north to shallows for 5m safety stop. SMB for surface pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'chicken-reef',name:'Chicken Reef',area:'Dampier Strait',areaSlug:'dampier-strait',rank:6,type:'Reef',access:'Boat',minDepth:5,maxDepth:30,avgDepth:16,visibility:'15–30m',temp:'27–30°C',current:'Mild to strong',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Year-round — Oct–Dec excellent visibility',bestSeason:'Year-round',goodFor:['Reef diving','Pelagics','Photography','All levels','Reliable marine life'],facilities:['Sorido Bay Resort','Kri Eco Resort','Kri Island homestays'],lat:-0.545,lng:130.698,rating:4.7,reviews:198,description:'Named when Max Ammer joked his dive buddy "acted like a chicken" after pulling a knife on reef sharks. This sloping reef system is one of the most commonly visited sites in Raja Ampat — popular for very good reason. Large coral bommies, gorgonian fans, dense schools of fusiliers, surgeonfish, bluefin jacks, sweetlips, clown triggerfish. Barracuda, whitetip and blacktip reef sharks, giant trevally. Bumphead parrotfish in shallows. Wobbegong and crocodile fish on the bottom. Macro: pygmy seahorses, mantis shrimp, frogfish. Divided into 4 sub-sites: Chicken Reef, Chicken Bay, Sleeping Barracuda, Surgeonfish Slope.',marineLife:[{name:'Schooling fusiliers',frequency:'very common'},{name:'Blacktip reef shark',frequency:'common'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Wobbegong shark',frequency:'common'},{name:'Pygmy seahorse',frequency:'occasional'}],safetyNotes:['Reef hook NOT typically required','Sloping reef allows depth adjustment to manage current','Monitor depth on outer reef edge'],briefing:'Boat drop on north (rising current) or south (falling current) end. Fast descent to seamount top. Circuit of reef sections: wall/gorgonian side, sandy slope, swim-throughs, shallow coral garden. Ascend from shallows for safety stop. SMB for pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'arborek-jetty',name:'Arborek Jetty',area:'Dampier Strait',areaSlug:'dampier-strait',rank:7,type:'Reef',access:'Boat',minDepth:5,maxDepth:18,avgDepth:10,visibility:'15–25m',temp:'27–30°C',current:'None to mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round — excellent dusk/night dive',bestSeason:'Year-round',goodFor:['Beginners','Night diving','Macro','Photography','Jetty diving'],facilities:['Arborek Dive Homestay','Arborek Dive Shop','Mawar Dive Homestay','Village facilities'],lat:-0.571,lng:130.531,rating:4.7,reviews:176,description:'A living artificial reef on the wooden jetty extending from Arborek village. The pylons are draped in soft coral and swarmed by glassfish and schooling snappers. Hundreds of juvenile batfish school beneath the structure. Wobbegong sharks rest camouflaged on sand at the jetty base. Epaulette (walking) sharks in shallow rubble. Macro paradise on pilings: nudibranchs, blennies, shrimps, electric clams, frogfish, Pontohi/Severn\'s pygmy seahorses. In season: manta rays gliding past. Night dive: walking sharks, cuttlefish, bioluminescence. Perfect introduction to Raja Ampat diving.',marineLife:[{name:'Schooling juvenile batfish',frequency:'very common'},{name:'Wobbegong shark',frequency:'common'},{name:'Epaulette shark',frequency:'occasional'},{name:'Pygmy seahorse',frequency:'common'},{name:'Nudibranch',frequency:'very common'}],safetyNotes:['Watch for boat traffic near the working jetty','Night dive requires torch and buddy','Shallow site — excellent buoyancy to avoid damaging coral on pilings'],briefing:'Descend from boat near jetty pilings or walk from Arborek village shore. Explore pylons at 5–12m — check every surface for macro life. Wobbegongs on sand below. Batfish school mid-water. Ascend along pilings. Surface swim to shore or boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'jetty' },

  { slug:'sawandarek-jetty',name:'Sawandarek Jetty',area:'Dampier Strait',areaSlug:'dampier-strait',rank:8,type:'Reef',access:'Boat',minDepth:5,maxDepth:25,avgDepth:14,visibility:'15–25m',temp:'27–30°C',current:'None to mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Turtles','Beginners','Reef diving','Photography','Marine life'],facilities:['Napoleon Sawandarek Homestay','Erens Guest House','Mansuar homestays'],lat:-0.591,lng:130.549,rating:4.7,reviews:143,description:'"Turtle City" — a natural bay on Mansuar with no current and extraordinary diversity. Numerous friendly green turtles including a massive resident female in rock crevices. Giant rose-shaped hard corals spreading across the slope. Thick schools of yellow snapper. Healthy reef with massive sea fans, anemones, giant clams. Macro: nudibranchs, pipefish, blue-ringed octopus, pygmy seahorses. A school of batfish "buddy up" with divers for the entire dive. Reef sharks, barracuda. Village is Seventh Day Adventist — Saturday limited services.',marineLife:[{name:'Green sea turtle',frequency:'very common'},{name:'Schooling yellow snapper',frequency:'very common'},{name:'Batfish',frequency:'very common'},{name:'Reef shark',frequency:'occasional'},{name:'Blue-ringed octopus',frequency:'occasional'}],safetyNotes:['Calm conditions — ideal for all levels','Village Saturday rest day — limited services','Respect turtles — observe only, no chasing'],briefing:'Boat drop near jetty. Descend on gently sloping reef. Explore coral gardens at 5–20m. Resident turtles in rock crevices. Giant rose corals on the slope. Batfish will follow you for the dive. Ascend near jetty for safety stop. Surface for boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'mikes-point',name:"Mike\'s Point",area:'Dampier Strait',areaSlug:'dampier-strait',rank:9,type:'Reef',access:'Boat',minDepth:5,maxDepth:40,avgDepth:20,visibility:'15–30m',temp:'27–30°C',current:'Mild to strong — varies by section',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Year-round — tide timing crucial',bestSeason:'Year-round',goodFor:['Wall diving','Swim-throughs','Pelagics','Photography','Marine biodiversity'],facilities:['Sorido Bay Resort','Kri Eco Resort','Kri/Mansuar homestays'],lat:-0.567,lng:130.630,rating:4.8,reviews:167,description:'The most underrated site in the Dampier Strait — four completely different dive types in one circumnavigation: (1) Wall: soft corals, massive gorgonian fans, pygmy seahorses. (2) Sandy slope: garden eels, shrimp-goby partnerships. (3) Swim-throughs: glassfish swarms, whitetip reef sharks resting in caves. (4) Shallow reef: colourful hard coral as far as the eye can see. Named after Max Ammer\'s son. Site was bombed in WWII (mistaken for a Japanese warship) creating massive crevasses and swim-throughs. Reef hooks no longer permitted. Best as a double-dive day.',marineLife:[{name:'Glassfish swarms',frequency:'very common'},{name:'Whitetip reef shark',frequency:'common'},{name:'Gorgonian sea fan',frequency:'very common'},{name:'Garden eel',frequency:'common'},{name:'Pygmy seahorse',frequency:'common'}],safetyNotes:['Reef hooks no longer permitted — conservation regulation','Stronger currents on corners — calmer in swim-throughs','Best done as double dive to cover all sections'],briefing:'Circumnavigation dive — boat drop varies by current. Start on wall/gorgonian side. Move to sandy slope for garden eels. Enter swim-throughs — glassfish everywhere. Finish on shallow coral garden. Surface at shallow reef plateau (~8m) for boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'melissa-garden',name:"Melissa\'s Garden",area:'Fam Islands',areaSlug:'fam-islands',rank:10,type:'Reef',access:'Boat',minDepth:5,maxDepth:25,avgDepth:14,visibility:'15–30m',temp:'27–30°C',current:'None to mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Coral gardens','Macro','Photography','Beginners','Snorkelling'],facilities:['Papua Diving Resorts (1.5hr boat)','Fam Islands homestays'],lat:-0.300,lng:130.280,rating:4.9,reviews:221,description:'Named after the daughter of Raja Ampat diving pioneer Max Ammer. One of the world\'s most beautiful coral gardens — staghorn (Acropora), cabbage, plate, and brain corals in every direction, colours shifting between brown, blue, purple, and green. A "magically manicured garden." Shallow dense fragile reef demands excellent buoyancy — frog kicking strongly recommended. Schools of anthias, fusiliers, damselfish, surgeonfish, angelfish, lionfish, cuttlefish. Blacktip reef sharks, moray eels. Macro: pygmy seahorses, nudibranchs, ghost pipefish, ribbon eels. Hawksbill turtles, giant clams. Save ample bottom time for the shallow coral garden at 5–10m.',marineLife:[{name:'Staghorn coral (Acropora)',frequency:'very common'},{name:'Pygmy seahorse',frequency:'common'},{name:'Hawksbill turtle',frequency:'common'},{name:'Blacktip reef shark',frequency:'occasional'},{name:'Nudibranch',frequency:'very common'}],safetyNotes:['Excellent buoyancy essential — coral is extremely fragile','Frog kicking strongly recommended — no flutter kicks','Stay high if trim is not solid'],briefing:'Drop on south side of island. Descend along sloping reef to sandy bottom at 25m. Explore coral garden on the ascent. Spend maximum time at 5–10m in the shallow coral garden between the pinnacles. Safety stop in the shallows. SMB or boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'friwen-wall',name:'Friwen Wall',area:'Dampier Strait',areaSlug:'dampier-strait',rank:11,type:'Wall',access:'Boat',minDepth:2,maxDepth:25,avgDepth:14,visibility:'15–25m',temp:'27–30°C',current:'None to strong — best at turn of tide',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Year-round — turn of tide for calm conditions',bestSeason:'Year-round',goodFor:['Wall diving','Macro photography','Marine life','Photography'],facilities:['Friwen village homestays (4 community-run)','Friwen Mangrove Eco Lodge','Kri/Mansuar resorts'],lat:-0.454,lng:130.725,rating:4.7,reviews:154,description:'The only true wall dive in central Raja Ampat. Vertical limestone cliffs between Friwen and Friwenbonda islands plunge to 25m, covered top to bottom with gorgonian fans, whip coral, sponges, and soft corals in neon pinks, deep purples, and electric oranges. Two small caves at the start. Turtles glide along the wall. Macro paradise: Pontohi and Denise\'s pygmy seahorses, flabellina nudibranchs, blennies, ghost pipefish, crabs, shrimps. Blacktip reef sharks, wobbegong sharks. Surface interval on tiny Friwenbonda islet with its white-sand cove is a highlight. Bring macro camera with lighting rather than wide-angle.',marineLife:[{name:'Gorgonian sea fan',frequency:'very common'},{name:'Pygmy seahorse',frequency:'very common'},{name:'Green sea turtle',frequency:'common'},{name:'Nudibranch',frequency:'very common'},{name:'Wobbegong shark',frequency:'occasional'}],safetyNotes:['Dive at turn of tide — peak tides create strong currents between the islands','Small caves are overhead environments — appropriate precautions','Visibility can be reduced in cliff shadow — bring dive light'],briefing:'Positive backroll entry at northern tip of Friwenbonda, in channel between islands. Drop to 20m. Drift west along the wall — inspect every crack and fan coral for pygmy seahorses. Two small caves at start — torch required. Western end: ascend up sloping reef. Safety stop at 2–5m. Boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'wall' },

  { slug:'mioskon',name:'Mioskon',area:'Dampier Strait',areaSlug:'dampier-strait',rank:12,type:'Reef',access:'Boat',minDepth:2,maxDepth:30,avgDepth:12,visibility:'15–25m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round — excellent night dive',bestSeason:'Year-round',goodFor:['Reef diving','All levels','Night diving','Macro','Schooling fish'],facilities:['Raja Ampat Dive Resort (10 min)','Kri/Mansuar homestays'],lat:-0.476,lng:130.770,rating:4.7,reviews:143,description:'Known as a "fishy" site. V-shaped reef around Mioskon Island with massive formations of yellowtail and blue-lined snapper. Wobbegong sharks camouflaged under bommies. Napoleon wrasse, large groupers, jacks, fusiliers, bumphead parrotfish, pagoda fish. Macro: Pontohi and Denise\'s pygmy seahorses, peacock mantis shrimp, blue-ringed octopus (rare), nudibranchs. Giant clam at 9m — one of the largest in the area. Orange sea fans with feather stars. Perfect check-dive site due to easy conditions. Night dive: sponge crabs, walking sharks, harlequin shrimps, banded sea snakes.',marineLife:[{name:'Schooling blue-lined snapper',frequency:'very common'},{name:'Wobbegong shark',frequency:'common'},{name:'Giant clam',frequency:'common'},{name:'Pygmy seahorse',frequency:'common'},{name:'Napoleon wrasse',frequency:'common'}],safetyNotes:['Reef top at 2m — watch buoyancy in shallows','Night dive requires torch and buddy','Banded sea snakes — do not approach'],briefing:'Positive entry on current side. Drift toward southeastern tip. Visit giant clam at 9m. Check bommies and overhangs for wobbegong sharks. Cruise coral garden at 7–9m for safety stop. Surface for boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'batu-lima',name:'Batu Lima',area:'Dampier Strait',areaSlug:'dampier-strait',rank:13,type:'Reef',access:'Boat',minDepth:3,maxDepth:24,avgDepth:14,visibility:'15–25m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round — famous for night dives',bestSeason:'Year-round',goodFor:['Reef diving','Night diving','Macro','Coral gardens','Walking sharks'],facilities:['Gam Island homestays','Kri/Mansuar resorts'],lat:-0.441,lng:130.773,rating:4.8,reviews:167,description:'Five Rocks — five connected rock formations at the pass into Kabui Bay. Slopes, ledges, and canyons between the rocks create a labyrinth of marine habitats. Schools of pickhandle barracuda, red snappers, fusiliers, batfish, surgeonfish. Blacktip and whitetip reef sharks. Blue-spotted stingrays, crocodile fish, hawksbill turtles. Brilliant purple coral fans covering walls just metres from the surface. Electric clams. Night dive FAMOUS for epaulette (walking) sharks emerging from coral and "walking" across the seafloor. One of the most popular sites — many guests request multiple return visits.',marineLife:[{name:'Epaulette shark',frequency:'very common (night)'},{name:'Schooling barracuda',frequency:'very common'},{name:'Blacktip reef shark',frequency:'common'},{name:'Purple coral fan',frequency:'very common'},{name:'Hawksbill turtle',frequency:'common'}],safetyNotes:['Rocks connected — can swim between at high tide','Night dive requires torch and buddy — walking sharks active in shallows','Canyons between rocks concentrate current — check flow before entering'],briefing:'Descend on northeastern side, follow slope to ~24m. Swim through canyons between rocks — concentrate of marine life. Purple fans at 3–10m near surface. Night: walking sharks emerge from coral. Ascend through canyons for safety stop. Surface for pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'citrus-ridge',name:'Citrus Ridge',area:'Gam Island',areaSlug:'gam-island',rank:14,type:'Reef',access:'Boat',minDepth:5,maxDepth:24,avgDepth:14,visibility:'15–25m',temp:'27–30°C',current:'Mild to moderate — protected from Dampier Strait',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Reef diving','Schooling fish','Photography','Beginners','Coral gardens'],facilities:['Gam Island homestays (Corepen, Kordiris)','Biodiversity Eco Resort','Meridian Adventure Dive Resort'],lat:-0.476,lng:130.633,rating:4.8,reviews:134,description:'A channel separating Gam from Yanggelo Island. The namesake pinnacle at ~14m is covered in the most incredible coral growth — deep oranges, yellows, reds, and greens like swimming through a field of citrus fruit. Large sponge formations, coral fans, soft coral. Nutrient-rich mangrove channel creates exceptional fish density. A "corridor" of batfish (in huge numbers), barracuda, and trevally at the channel mouth. Crocodile fish, angelfish, sweetlips, lionfish. More relaxed than nearby Mayhem. Gold for wide-angle photographers.',marineLife:[{name:'Citrus-coloured coral pinnacle',frequency:'very common'},{name:'Schooling batfish',frequency:'very common'},{name:'Barracuda',frequency:'common'},{name:'Crocodile fish',frequency:'common'},{name:'Angelfish',frequency:'very common'}],safetyNotes:['Protected from main Dampier Strait — gentler conditions','Currents can intensify in main channel mouth','Beginners welcome but watch depth at channel edges'],briefing:'Entry from north or south depending on current. Descend onto gentle slope to citrus pinnacle at 14m. Wide-angle time here. Move toward channel mouth for batfish and barracuda corridor. Ascend from reef formation. SMB or boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },

  { slug:'wayag-wall',name:'Wayag Wall',area:'Wayag',areaSlug:'wayag',rank:15,type:'Wall',access:'Boat',minDepth:5,maxDepth:40,avgDepth:22,visibility:'20–40m',temp:'27–30°C',current:'Moderate to strong',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Oct–Apr',bestSeason:'Oct–Apr',goodFor:['Wall diving','Pelagics','Remote diving','Photography'],facilities:['Liveaboards only — remote location'],lat:-0.218,lng:130.097,rating:4.9,reviews:89,description:'A remote wall dive in the iconic Wayag lagoon system, surrounded by dramatic karst limestone mushroom islands. Healthy vertical wall with exceptional soft coral and sponge coverage. Schools of fusiliers and surgeonfish. Reef sharks, Napoleon wrasse, turtles. Pristine conditions due to remote location. Often combined with the Wayag viewpoint — one of the most photographed landscapes in Indonesia.',marineLife:[{name:'Reef shark',frequency:'common'},{name:'Napoleon wrasse',frequency:'common'},{name:'Schooling fusilier',frequency:'very common'},{name:'Sea turtle',frequency:'common'},{name:'Soft coral',frequency:'very common'}],safetyNotes:['Remote location — liveaboard only','Stronger currents than central Raja Ampat sites','Limited emergency facilities — dive conservatively'],briefing:'Liveaboard drop at wall. Descend and drift along vertical face. Pelagics patrol the wall edge. Ascend to reef top for safety stop. SMB for liveaboard pickup.',emergencyContact:'DAN Asia Pacific: +61 8 8212 9242 | Waisai Hospital: +62 951 21020',diagramType:'wall' },

  { slug:'p47-wreck',name:'P-47 Plane Wreck',area:'Batanta',areaSlug:'batanta',rank:16,type:'Wreck',access:'Boat',minDepth:22,maxDepth:38,avgDepth:30,visibility:'10–25m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Oct–Apr',bestSeason:'Oct–Apr',goodFor:['Wreck diving','WWII history','Photography','Advanced diving'],facilities:['Papua Paradise Eco Resort','Liveaboards'],lat:-0.880,lng:130.630,rating:4.7,reviews:67,description:'A WWII American P-47 Thunderbolt fighter aircraft lying upright on the sandy seafloor at 22–38m. The aircraft is intact with both wings, fuselage, propeller, and cockpit recognisable. Soft corals and sponges encrust the fuselage. Schools of glassfish swarm around the cockpit. Moray eels inside. Lying in clear water with excellent visibility on calm days. A piece of WWII history in extraordinary condition.',marineLife:[{name:'Glassfish',frequency:'very common'},{name:'Moray eel',frequency:'common'},{name:'Soft coral',frequency:'common'},{name:'Barracuda',frequency:'occasional'}],safetyNotes:['Deep wreck — Advanced certification required','Strict NDL management — limited bottom time at 38m','Do not penetrate wreck — structure unstable in places'],briefing:'Boat drop over sandy seafloor. Descend to aircraft at 22–38m. Circumnavigate the intact fuselage, wings, and propeller. Glassfish swarm the cockpit. Limited bottom time — strict NDL. Ascend on sandy slope. Safety stop at 5m. SMB for boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'wreck' },

  { slug:'boo-windows',name:'Boo Windows',area:'Misool',areaSlug:'misool',rank:17,type:'Wall',access:'Boat',minDepth:5,maxDepth:40,avgDepth:20,visibility:'15–30m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Oct–Apr',bestSeason:'Oct–Apr',goodFor:['Wall diving','Swim-throughs','Photography','Marine life'],facilities:['Misool Eco Resort','Liveaboards'],lat:-2.017,lng:130.217,rating:4.8,reviews:112,description:'Famous limestone "windows" — swim-throughs cut through the rock formations of Misool. Lush gorgonian walls, massive sponges, schooling fish visible through the arched windows. Incredible soft coral coverage in reds, oranges, and purples. Turtles, reef sharks, Napoleon wrasse. Outstanding wide-angle photography.',marineLife:[{name:'Gorgonian sea fan',frequency:'very common'},{name:'Soft coral',frequency:'very common'},{name:'Green sea turtle',frequency:'common'},{name:'Napoleon wrasse',frequency:'common'},{name:'Schooling fish',frequency:'very common'}],safetyNotes:['Swim-throughs — check air supply before entering','Currents can intensify inside windows','Watch for surge'],briefing:'Boat entry. Descend to wall. Navigate through limestone windows — glassfish inside. Gorgonians line the walls. Continue along outer wall. Ascend for safety stop. SMB or boat pickup.',emergencyContact:'Misool Eco Resort clinic | DAN Asia Pacific: +61 8 8212 9242',diagramType:'wall' },

  { slug:'friwin-banda',name:'Friwin Banda',area:'Dampier Strait',areaSlug:'dampier-strait',rank:18,type:'Reef',access:'Boat',minDepth:2,maxDepth:28,avgDepth:14,visibility:'15–25m',temp:'27–30°C',current:'None to mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Coral gardens','Beginners','Macro','Snorkelling'],facilities:['Friwen village homestays','Friwen Mangrove Eco Lodge'],lat:-0.462,lng:130.731,rating:4.6,reviews:98,description:'The calm counterpart to Friwen Wall — a gentle coral garden on the Friwenbonda side with diverse coral formations and excellent macro life. Ribbon eels and endemic garden eels (found only in Raja Ampat) on the sandy patches. Blue-spotted stingrays. Nudibranchs, shrimps, crabs, and small reef fish among the coral. A relaxed, contemplative dive perfect after the drama of Friwen Wall.',marineLife:[{name:'Ribbon eel',frequency:'common'},{name:'Endemic garden eel',frequency:'occasional'},{name:'Blue-spotted stingray',frequency:'common'},{name:'Nudibranch',frequency:'very common'}],safetyNotes:['Gentle conditions — suitable for all levels','Endemic garden eels — approach slowly and stay low'],briefing:'Boat drop on sloping reef. Descend gently. Search sandy patches for ribbon eels and endemic garden eels. Blue-spotted stingrays on sandy bottom. Macro life in coral formations. Gradual ascent up slope for safety stop. Boat pickup.',emergencyContact:'Waisai Hospital: +62 951 21020 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'boat' },
]
export function getRajaAmpatSiteBySlug(slug:string){return RAJA_AMPAT_SITES.find(s=>s.slug===slug)}

