export const BORNEO_SITES: DiveSite[] = [
  // ── DERAWAN ISLAND ───────────────────────────────────────────────────────
  { slug:'derawan-jetty',name:'The Jetty',area:'Derawan Island',areaSlug:'derawan-island',rank:1,type:'Reef',access:'Shore',minDepth:2,maxDepth:15,avgDepth:8,visibility:'3–15m',temp:'27–30°C',current:'None to very mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round; excellent night dive',bestSeason:'Year-round',goodFor:['Jetty diving','Macro','Night diving','Beginners','Turtles'],facilities:['Scuba Junkie Sangalaki','Derawan Dive Lodge','Derawan Resort'],lat:2.2833,lng:118.2333,rating:4.8,reviews:198,description:'One of the best pier dives in Indonesia. The wooden pillars of Derawan village jetty create a superb artificial reef teeming with macro life. Green turtles are almost guaranteed, resting under the jetty structure. Day dive: frogfish, ghost pipefish, nudibranchs, crustaceans, blue-ringed octopus, stonefish, scorpionfish, leaf fish, giant moray eels. Night dive: flamboyant cuttlefish, hunting octopus, sleeping parrotfish, baby guitar sharks at sunset in the shallows. A small wreck at ~20m nearby is covered in beautiful soft corals. Motorbike visible in the shallows. Turtle sightings on every single dive.',marineLife:[{name:'Green sea turtle',frequency:'very common'},{name:'Ghost pipefish',frequency:'common'},{name:'Flamboyant cuttlefish',frequency:'common'},{name:'Blue-ringed octopus',frequency:'occasional'},{name:'Giant moray eel',frequency:'common'}],safetyNotes:['Shore entry — watch for boat traffic from working jetty','Night dive: torch essential','Baby guitar sharks in shallows at sunset — observe only, never approach'],briefing:'Descend from jetty stairs or beach near pier. Explore pilings at 5–12m — check every surface. Turtles rest under structure. Wreck at ~20m nearby. Night dive: search sandy areas and rubble for nocturnal critters.',emergencyContact:'Berau General Hospital: +62 554 21118 | DAN Asia Pacific: +61 8 8212 9242',diagramType:'jetty' },

  { slug:'macromania',name:'Macromania',area:'Derawan Island',areaSlug:'derawan-island',rank:2,type:'Muck',access:'Boat',minDepth:5,maxDepth:20,avgDepth:12,visibility:'10–20m',temp:'27–30°C',current:'Mild to none',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round; excellent night dive',bestSeason:'Year-round',goodFor:['Macro','Muck diving','Photography','Rare critters'],facilities:['Scuba Junkie Sangalaki','Derawan Dive Lodge'],lat:2.290,lng:118.240,rating:4.7,reviews:143,description:'Derawan Island\'s premier macro dive site. Rubble and sand bottom where patient divers are rewarded with some of the strangest and most sought-after critters in the Coral Triangle. Orangutan crabs, decorator crabs, hairy octopus, bobtail squid regularly sighted. As dive progresses toward reef: stonefish, multiple frogfish species, scorpionfish, and cuttlefish. Also excellent night dive revealing even more cryptic creatures. Named for its extraordinary concentration of macro life — a critter photographer\'s paradise and must-visit for underwater photographers.',marineLife:[{name:'Orangutan crab',frequency:'common'},{name:'Hairy octopus',frequency:'common'},{name:'Bobtail squid',frequency:'common'},{name:'Frogfish',frequency:'very common'},{name:'Pygmy seahorse',frequency:'occasional'}],safetyNotes:['Move very slowly — critters perfectly camouflaged','Perfect buoyancy essential — never touch bottom'],briefing:'Back-roll entry from dive boat. Slow descent onto rubble and sand. Zigzag search pattern. Move toward reef for frogfish and scorpionfish. Night dive: even more cryptic creatures emerge.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'shore' },

  { slug:'derawan-house-reef',name:'Derawan House Reef',area:'Derawan Island',areaSlug:'derawan-island',rank:3,type:'Reef',access:'Shore',minDepth:2,maxDepth:18,avgDepth:10,visibility:'10–20m',temp:'27–30°C',current:'Very mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round; great night dive',bestSeason:'Year-round',goodFor:['Turtles','Beginners','Night diving','Macro','House reef'],facilities:['Extra Divers Virgin Cocoa','Multiple resorts along coast'],lat:2.285,lng:118.235,rating:4.6,reviews:167,description:'Easy, relaxed diving along Derawan\'s shoreline suitable for all levels. Gently sloping reef with colorful hard and soft corals. Turtle sightings extraordinarily common — dozens of green turtles in a single dive is normal. Seahorses, leaf fish, blue-ringed octopus, frogfish. Juvenile guitar sharks (critically endangered) spotted in the shallows at sunset — a truly special experience unique to Derawan. Night dive: flamboyant cuttlefish, hunting octopus, nocturnal critters. Some resorts have a 4km stretch of outer reef directly accessible as a house reef.',marineLife:[{name:'Green turtle',frequency:'very common'},{name:'Seahorse',frequency:'common'},{name:'Leaf fish',frequency:'common'},{name:'Juvenile guitar shark',frequency:'occasional (sunset)'},{name:'Frogfish',frequency:'common'}],safetyNotes:['Step entry from stilted bungalows or beach — shuffle feet','Guitar sharks critically endangered — observe from distance, never chase','Night dive: torch and buddy essential'],briefing:'Step directly into water from resort. Descend on gently sloping reef. Turtles everywhere at 5–15m. Check sand patches for seahorses and leaf fish. Evening: watch shallow areas for guitar sharks. Night dive: full transformation with nocturnal critters.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'shore' },

  { slug:'darma-fonsi-point',name:'Darma & Fonsi Point',area:'Derawan Island',areaSlug:'derawan-island',rank:4,type:'Reef',access:'Boat',minDepth:10,maxDepth:30,avgDepth:18,visibility:'15–25m',temp:'27–30°C',current:'Mild',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Reef diving','Wide-angle photography','Macro','Sea fans'],facilities:['Scuba Junkie Sangalaki','Liveaboards'],lat:2.300,lng:118.250,rating:4.5,reviews:98,description:'Two productive sites on the less-visited side of Derawan Island. Darma Point features large sea fans, black coral, and whip gorgonians at 18–24m with longnose hawkfish, schooling fusiliers, and pyramid butterflyfish. Dozens of cornetfish, batfish at cleaning stations, dwarf cuttlefish, twinspot lionfish, and bamboo sharks documented. Fonsi Point offers similar coral diversity with excellent wide-angle photography — pristine coral formations with very little diver traffic. Both sites produce reliable turtle encounters.',marineLife:[{name:'Bamboo shark',frequency:'occasional'},{name:'Batfish (at cleaning station)',frequency:'common'},{name:'Dwarf cuttlefish',frequency:'common'},{name:'Longnose hawkfish',frequency:'common'},{name:'Cornetfish',frequency:'very common'}],safetyNotes:['Less-visited — carry SMB','Bamboo sharks: observe only, do not approach'],briefing:'Back-roll entry. Descend to reef at 15–20m. Explore sea fans and black coral at Darma. Drift to Fonsi for wide-angle coral formations. Cleaning stations at both sites.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  // ── SANGALAKI ISLAND ────────────────────────────────────────────────────
  { slug:'manta-parade',name:'Manta Parade',area:'Sangalaki Island',areaSlug:'sangalaki-island',rank:5,type:'Reef',access:'Boat',minDepth:5,maxDepth:18,avgDepth:10,visibility:'15–25m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round; best Mar–Dec',bestSeason:'Mar–Dec',goodFor:['Manta rays','Marine life','Photography','All levels','Snorkelling'],facilities:['Sangalaki Resort','Scuba Junkie Sangalaki','Maratua resorts'],lat:2.050,lng:118.350,rating:5.0,reviews:267,description:'The signature dive site of Sangalaki and one of the most reliable manta ray encounters in the world. Part of the "Manta Highway" — mantas parade up and down this underwater corridor from all directions. 65% of all manta feeding events in the archipelago are recorded here. Up to 42 mantas observed in single aggregations. Research by Marine Megafauna Foundation identified 155 individual reef manta rays from 846 encounters. Coral ridges rising and falling like small underwater hills, covered in gorgonian fans, barrel sponges, and feather stars. Small coral heads home to incredible reef fish diversity. Snorkelling can be as good as diving — mantas often feed at the surface. Even without mantas, the marine life is spectacular.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Green turtle',frequency:'very common'},{name:'Leopard shark',frequency:'occasional'},{name:'Giant moray eel',frequency:'common'},{name:'Gorgonian sea fan',frequency:'very common'}],safetyNotes:['Strict manta etiquette — no chasing, no touching, no hovering above','Mantas can startle — stay calm and still when they approach','Snorkelling excellent — mantas feed at surface'],briefing:'Back-roll entry near coral ridges. Descend to 5–15m along the manta highway. Hover low and still. Mantas approach from all directions — do not swim at them. Follow at distance if they move. SMB for pickup.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  { slug:'manta-avenue',name:'Manta Avenue',area:'Sangalaki Island',areaSlug:'sangalaki-island',rank:6,type:'Reef',access:'Boat',minDepth:5,maxDepth:18,avgDepth:10,visibility:'15–25m',temp:'27–30°C',current:'Mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Manta rays','Cleaning station','Beginners','Photography'],facilities:['Sangalaki Resort','Scuba Junkie Sangalaki'],lat:2.055,lng:118.345,rating:4.9,reviews:198,description:'The western start of the famous manta highway along Sangalaki\'s north coast. Distinctive coral steps topography where mantas come to cleaning stations to have parasites removed by cleaner wrasse. Beside the manta action: elegant fire gobies and dancing gobies at the base of coral steps — some of the most photogenic small fish in Indonesian waters. Reliable cleaning station means mantas hover and circle patiently — giving divers extended time to observe and photograph. This is where to position if you want quiet, undisturbed manta encounters.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Fire goby',frequency:'very common'},{name:'Dancing goby',frequency:'very common'},{name:'Green turtle',frequency:'common'}],safetyNotes:['No touching or riding mantas at cleaning stations','Stay low — hovering above cleaning station disturbs mantas','Position downstream of cleaning station'],briefing:'Back-roll entry at coral steps. Position at cleaning station at 8–12m. Stay low and still. Mantas will circle cleaning station repeatedly. Fire gobies and dancing gobies at base of coral steps.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  { slug:'manta-run',name:'Manta Run',area:'Sangalaki Island',areaSlug:'sangalaki-island',rank:7,type:'Reef',access:'Boat',minDepth:5,maxDepth:18,avgDepth:10,visibility:'15–25m',temp:'27–30°C',current:'Mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Manta rays','Macro','Reef diving','Photography'],facilities:['Sangalaki Resort','Scuba Junkie Sangalaki'],lat:2.048,lng:118.358,rating:4.8,reviews:167,description:'The eastern extent of the manta highway — 30% of all manta feeding events in the archipelago are recorded here. Topography changes to rocky coral outcrops and bommies covered in gorgonian fans, soft corals, and barrel sponges. Leaf fish and frogfish hide in the numerous crevices and overhangs — and divers can witness them actively preying on cardinalfish during feeding times. Even without mantas, the diverse bommie landscape rewards slow exploration. Combine with Manta Parade and Manta Avenue for a full day on the manta highway.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Leaf fish',frequency:'common'},{name:'Frogfish',frequency:'common'},{name:'Cardinalfish',frequency:'very common'},{name:'Gorgonian sea fan',frequency:'very common'}],safetyNotes:['Eastern end — currents slightly stronger here','Rocky bommies — watch depth and buoyancy'],briefing:'Back-roll entry at rocky bommies. Explore outcrops for leaf fish and frogfish in crevices. Watch for mantas in the blue above. Drift gently east along the reef.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  { slug:'turtle-town-sangalaki',name:'Turtle Town',area:'Sangalaki Island',areaSlug:'sangalaki-island',rank:8,type:'Reef',access:'Boat',minDepth:5,maxDepth:18,avgDepth:10,visibility:'15–25m',temp:'27–30°C',current:'Mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Year-round; nesting peaks Apr–Sep',bestSeason:'Year-round',goodFor:['Turtles','Beginners','Marine life','Photography'],facilities:['Sangalaki Resort','Scuba Junkie Sangalaki'],lat:2.040,lng:118.340,rating:4.8,reviews:176,description:'Named for its extraordinary green turtle population — the most turtle-dense site in the archipelago. Flat topography with gullies and stony ridges ideal for green turtles to stop for a bite or rest. 20–30 turtle nests laid per night on Sangalaki\'s beaches during peak season — mating activities in the water are extensive. Divers find turtles feeding, mating, and resting throughout the dive. Along with turtles: octopus, giant cuttlefish, popcorn crabs, shy mandarinfish emerging at dusk, and flamboyantly colored nudibranchs. A site where you lose count of how many turtles you see.',marineLife:[{name:'Green turtle',frequency:'very common'},{name:'Giant cuttlefish',frequency:'common'},{name:'Mandarinfish',frequency:'occasional (dusk)'},{name:'Nudibranch',frequency:'very common'},{name:'Octopus',frequency:'common'}],safetyNotes:['Turtle mating: observe from distance — do not interrupt','Mandarinfish at dusk: arrive 30 min before sunset','Indonesia\'s most important green turtle nesting site — conservation rules apply'],briefing:'Back-roll entry. Descend on flat reef. Green turtles feeding in gullies. Ridges and stony outcrops for resting turtles. Check sandy patches for octopus and cuttlefish. Dusk: mandarinfish emerge from coral.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  { slug:'lighthouse-reef-sangalaki',name:'Lighthouse Reef',area:'Sangalaki Island',areaSlug:'sangalaki-island',rank:9,type:'Reef',access:'Boat',minDepth:10,maxDepth:25,avgDepth:15,visibility:'15–25m',temp:'27–30°C',current:'Mild',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Wrecks','Macro','Pygmy seahorse','Photography'],facilities:['Sangalaki Resort','Scuba Junkie Sangalaki'],lat:2.045,lng:118.362,rating:4.7,reviews:134,description:'Named for the lighthouse on the eastern tip of Sangalaki. Two small wrecks create interesting artificial reef habitats. The older wreck is identified by prolific soft corals (dendronephthya) and magnificent sea anemones. Among the gorgonian fans: pygmy seahorses for keen-eyed divers. The sandy bottom is dotted with giant Tridacna clams. Sweetlips, gobies, scorpionfish, jawfish, and ribbon eels throughout the reef structure. Night dive: highly recommended — site transforms with nocturnal critters emerging from the soft coral structures.',marineLife:[{name:'Pygmy seahorse',frequency:'occasional'},{name:'Giant Tridacna clam',frequency:'common'},{name:'Ribbon eel',frequency:'common'},{name:'Dendronephthya soft coral',frequency:'very common'},{name:'Jawfish',frequency:'occasional'}],safetyNotes:['Two wrecks at site — do not penetrate small wrecks','Giant clams: do not touch or stand near'],briefing:'Back-roll entry near lighthouse. Locate two small wrecks at 15–22m. Inspect soft corals for pygmy seahorses. Sandy patches for jawfish and ribbon eels. Giant clams throughout. Night dive highly rewarding.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  { slug:'high-garden',name:'High Garden',area:'Sangalaki Island',areaSlug:'sangalaki-island',rank:10,type:'Reef',access:'Boat',minDepth:10,maxDepth:25,avgDepth:15,visibility:'15–25m',temp:'27–30°C',current:'Mild',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Barrel sponges','Photography','Wide-angle','Marine life'],facilities:['Sangalaki Resort','Scuba Junkie Sangalaki'],lat:2.058,lng:118.352,rating:4.8,reviews:154,description:'One of the most visually stunning dive sites in the Derawan Archipelago — top pick for underwater photographers. Begins over a coral hill with a sandy channel beside it. The defining feature is massive red barrel sponges (Xestospongia testudinaria) — favourite hiding place for hairy squat lobsters. Fusiliers flow alongside divers. Regular surprise appearances by leopard sharks, giant moray eels. Manta rays occasionally cruise by from the nearby manta highway. The rich reefscape, dramatic sponge formations, and reliable large animal encounters make this a consistent highlight of any Sangalaki trip.',marineLife:[{name:'Massive red barrel sponge',frequency:'very common'},{name:'Hairy squat lobster',frequency:'very common'},{name:'Leopard shark',frequency:'occasional'},{name:'Giant moray eel',frequency:'common'},{name:'Schooling fusilier',frequency:'very common'}],safetyNotes:['Barrel sponges: do not touch — extremely fragile','Leopard sharks: remain stationary and calm when encountered'],briefing:'Back-roll entry over coral hill. Descend to channel beside hill. Find barrel sponges at 15–20m — inspect each for hairy squat lobsters. Fusiliers swarm throughout. Watch for leopard sharks on sandy patches.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  // ── KAKABAN ISLAND ──────────────────────────────────────────────────────
  { slug:'barracuda-point-kakaban',name:'Barracuda Point',area:'Kakaban Island',areaSlug:'kakaban-island',rank:11,type:'Wall',access:'Boat',minDepth:10,maxDepth:40,avgDepth:25,visibility:'15–30m',temp:'27–30°C',current:'Strong — exhilarating drift',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Mar–Oct; incoming or slack tide',bestSeason:'Mar–Oct',goodFor:['Drift diving','Schooling fish','Sharks','Pelagics','Big fish'],facilities:['Accessed from Derawan or Maratua — min 4 day package'],lat:2.155,lng:118.510,rating:5.0,reviews:234,description:'One of the premier drift dives in Indonesia and the most famous site in the Derawan Archipelago. Follows the top of a sheer wall around the point where two walls converge. As the corner beckons, the concentration of pelagic life intensifies dramatically. Swirling schools of chevron barracuda fill the sea in breathtaking tornado formations, joined by big-eye trevally, jackfish, and tuna. Whitetip, blacktip, and grey reef sharks common. Leopard sharks, manta rays, eagle rays, and mobula rays may cruise by. Some operators (Scuba Junkie Sangalaki) do NOT dive Kakaban at all due to down-current risks — choose operators with strong safety records.',marineLife:[{name:'Chevron barracuda (tornado)',frequency:'very common'},{name:'Big-eye trevally',frequency:'very common'},{name:'Grey reef shark',frequency:'common'},{name:'Manta ray',frequency:'occasional'},{name:'Eagle ray',frequency:'common'}],safetyNotes:['ADVANCED ONLY — AOW certification required','Strong down-currents possible — stay alert','Some operators refuse this site for safety reasons — heed their advice','Minimum 20 logged dives recommended by many operators'],briefing:'Back-roll from boat. Follow wall around the point. Concentrate of pelagic life at corner — hook in if available. Watch for barracuda tornadoes in the blue. Exit before corner if current strengthens. SMB for pickup.',emergencyContact:'Berau General Hospital: +62 554 21118 | Nearest chamber: Balikpapan',diagramType:'wall' },

  { slug:'meditation-wall',name:'Meditation Wall',area:'Kakaban Island',areaSlug:'kakaban-island',rank:12,type:'Wall',access:'Boat',minDepth:15,maxDepth:40,avgDepth:28,visibility:'15–30m',temp:'27–30°C',current:'Strong',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Early morning for thresher sharks',bestSeason:'Mar–Oct',goodFor:['Thresher sharks','Drift diving','Wall diving','Big fish'],facilities:['Accessed from Derawan or Maratua'],lat:2.160,lng:118.505,rating:4.9,reviews:143,description:'Earned a reputation for incredible shark encounters — particularly thresher sharks. Close encounters with these elusive pelagic sharks reported by numerous divers. Nurse sharks, blacktip, and whitetip reef sharks also regularly patrol the dramatic walls adorned with sea fans. Thresher sharks typically appear in the early morning before the sun is high — plan the boat departure accordingly. The wall itself is spectacular in its own right with excellent sea fan coverage and strong current delivering nutrients to filter feeders.',marineLife:[{name:'Thresher shark',frequency:'occasional (early morning)'},{name:'Nurse shark',frequency:'common'},{name:'Blacktip reef shark',frequency:'common'},{name:'Whitetip reef shark',frequency:'common'},{name:'Gorgonian sea fan',frequency:'very common'}],safetyNotes:['ADVANCED ONLY — strong currents','Early morning timing critical for thresher shark encounters','Thresher sharks: do not approach — remain still'],briefing:'Very early morning departure. Back-roll at wall edge. Descend along wall. Threshers appear early morning in deeper blue. Nurse sharks on sandy ledges. Drift with current along wall face. SMB pickup.',emergencyContact:'Berau General Hospital: +62 554 21118 | Nearest chamber: Balikpapan',diagramType:'wall' },

  { slug:'blue-light-cave',name:'Blue Light Cave',area:'Kakaban Island',areaSlug:'kakaban-island',rank:13,type:'Wall',access:'Boat',minDepth:21,maxDepth:44,avgDepth:35,visibility:'15–25m',temp:'27–30°C',current:'Can be strong at exit',difficulty:'Advanced / Technical',minCert:'Advanced Open Water',bestTime:'Slack tide; experienced divers only',bestSeason:'Mar–Oct',goodFor:['Cave diving','Technical diving','Unique experience'],facilities:['Accessed from Derawan or Maratua — specialist operators only'],lat:2.158,lng:118.508,rating:4.9,reviews:89,description:'One of the most thrilling cave experiences in the Derawan Archipelago. The cave starts at a hole at the top of the wall, descends through a narrow chimney. At ~21m the chimney opens into a large cavern with the bottom at 30m. Swimming along the ceiling for ~120m leads to the exit — a long vertical crack at 44m (alternate exit at 64m). As divers swim through the cavern toward the exit, the blue light of the open sea creates an ethereal, unforgettable atmosphere. For experienced divers only. Low tide entry at 2m. Requires good air management and calm in enclosed spaces.',marineLife:[{name:'Cave formations',frequency:'very common'},{name:'Blue light exit phenomenon',frequency:'very common'}],safetyNotes:['EXPERIENCED DIVERS ONLY — overhead environment','120m swim through cavern — excellent air management required','Exit at 44m — strict NDL management','Do NOT enter at high tide — entrance closes','No overhead diving certification = no entry'],briefing:'Low tide entry at chimney hole in wall. Descend through narrow chimney. Opens at 21m into large cavern. Swim along ceiling for 120m toward blue light. Exit at 44m crack. Strict air management throughout.',emergencyContact:'Berau General Hospital: +62 554 21118 | Nearest chamber: Balikpapan — evacuation required',diagramType:'wall' },

  { slug:'kakaban-walls',name:'Kakaban Walls',area:'Kakaban Island',areaSlug:'kakaban-island',rank:14,type:'Wall',access:'Boat',minDepth:10,maxDepth:40,avgDepth:25,visibility:'15–30m',temp:'27–30°C',current:'Moderate to strong',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Mar–Oct',bestSeason:'Mar–Oct',goodFor:['Wall diving','Pygmy seahorse','Drift diving','Sharks','Photography'],facilities:['Accessed from Derawan or Maratua'],lat:2.162,lng:118.512,rating:4.8,reviews:176,description:'The outer walls of Kakaban offer some of the best wall diving in Indonesia. Steep limestone cliffs drop to the water\'s edge then plummet to 200m+. The walls are adorned with tiers of hanging soft corals, sea fans, and whip corals. Sea fan forests are excellent for pygmy seahorse searches. Strong currents attract pelagic species — shark sightings (whitetip, blacktip, grey reef, and occasional hammerhead) are common. Multiple wall sections can be combined into one dive or spread across different sites. Kakaban\'s walls rival the best in the Coral Triangle for sheer dramatic scale.',marineLife:[{name:'Pygmy seahorse',frequency:'common'},{name:'Whitetip reef shark',frequency:'common'},{name:'Hammerhead shark',frequency:'occasional'},{name:'Sea fan forest',frequency:'very common'},{name:'Leopard shark',frequency:'occasional'}],safetyNotes:['Multiple wall sections — agree with guide which section before entry','Walls drop to 200m+ — strict depth discipline','New divers: check dive at Derawan required first by most operators'],briefing:'Back-roll at agreed wall section. Descend along wall face. Inspect sea fans for pygmy seahorses. Drift with current. Watch blue for sharks. Ascend along wall for safety stop. SMB pickup.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'wall' },

  // ── MARATUA ATOLL ───────────────────────────────────────────────────────
  { slug:'big-fish-country',name:'Big Fish Country',area:'Maratua Atoll',areaSlug:'maratua-atoll',rank:15,type:'Wall',access:'Boat',minDepth:15,maxDepth:40,avgDepth:28,visibility:'20–40m',temp:'27–30°C',current:'Very strong — dangerous down-currents',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Mar–Oct; slack tide only',bestSeason:'Mar–Oct',goodFor:['Big fish','Pelagics','Sharks','Advanced diving'],facilities:['Liveaboards — specialist operators only; Nabucco Resort'],lat:2.175,lng:118.620,rating:4.9,reviews:112,description:'Named for the extraordinary concentration of large pelagic life — the most extreme and rewarding dive in the Derawan Archipelago. Schools of bumphead parrotfish, dogtooth tuna, giant trevally, Napoleon wrasse, hammerhead sharks, and thresher sharks pass through regularly. Ultra-clear visibility (20–40m) makes sightings dramatic and far-reaching. WARNING: Scuba Junkie Sangalaki does NOT dive this site due to dangerously strong down-currents (including small whirlpools), vertical walls with extreme depths, and 3+ hour boat trip to nearest medical facility. Only highly experienced divers with specialist operators in perfect conditions. This is not a site for anyone below Advanced level.',marineLife:[{name:'Bumphead parrotfish',frequency:'common'},{name:'Hammerhead shark',frequency:'occasional'},{name:'Dogtooth tuna',frequency:'common'},{name:'Napoleon wrasse',frequency:'common'},{name:'Thresher shark',frequency:'occasional'}],safetyNotes:['DANGEROUS — strong down-currents including whirlpools','Some top operators REFUSE this site on safety grounds','3+ hours from nearest medical facility','Slack tide only — strict timing','Advanced with specialist operator only'],briefing:'Specialist operator briefing required. Slack tide entry only. Immediate descent to wall. Watch for down-currents — abort dive if current reverses. Big fish in the blue. Controlled ascent. SMB mandatory.',emergencyContact:'Berau General Hospital: +62 554 21118 | Nearest chamber: Balikpapan — 3+ hours away',diagramType:'wall' },

  { slug:'turtle-traffic',name:'Turtle Traffic',area:'Maratua Atoll',areaSlug:'maratua-atoll',rank:16,type:'Reef',access:'Boat',minDepth:10,maxDepth:30,avgDepth:18,visibility:'20–40m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Turtles','Reef diving','Photography','Marine life'],facilities:['Maratua Paradise Resort','Noah Maratua Resort','Nabucco Resort'],lat:2.180,lng:118.615,rating:4.8,reviews:143,description:'Also known as Turtle Run — a site where green and hawksbill turtles cruise the reef in remarkable numbers, aided by the ultra-clear Maratua visibility. The clean open water of Maratua Atoll, far from the mainland, gives visibility that can exceed 40m on good days. Turtles glide serenely through the coral formations, often close enough to watch feeding behavior on the reef. Healthy hard coral formations, schooling fish, and regular pelagic visitors from the deeper atoll water complement the turtle encounters.',marineLife:[{name:'Green turtle',frequency:'very common'},{name:'Hawksbill turtle',frequency:'common'},{name:'Schooling jackfish',frequency:'common'},{name:'Napoleon wrasse',frequency:'occasional'}],safetyNotes:['Maratua current can increase unexpectedly — monitor throughout','Turtles: do not chase or block path'],briefing:'Back-roll entry. Descend on healthy coral reef at 10–20m. Turtles frequent all depths. Watch in the blue for passing pelagics — Napoleon wrasse and jacks common. Ultra-clear water allows sightings at distance.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'boat' },

  { slug:'gorgonzola',name:'Gorgonzola',area:'Maratua Atoll',areaSlug:'maratua-atoll',rank:17,type:'Wall',access:'Boat',minDepth:15,maxDepth:40,avgDepth:25,visibility:'20–40m',temp:'27–30°C',current:'Mild to moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Year-round',bestSeason:'Year-round',goodFor:['Gorgonians','Photography','Wall diving','Pygmy seahorse'],facilities:['Maratua Paradise Resort','Noah Maratua Resort'],lat:2.190,lng:118.608,rating:4.7,reviews:112,description:'Named for its extraordinary gorgonian sea fan formations that cover the wall like an underwater forest. Maratua\'s exceptional clarity (20–40m) makes the sea fan panoramas even more dramatic. Multiple species of pygmy seahorse hiding in the larger fans. Hairy squat lobsters on barrel sponges throughout the wall. Sharks and rays patrol the blue water in front of the wall. The combination of pristine wall structure, exceptional visibility, and diverse marine life makes Gorgonzola one of the most rewarding photography sites in the archipelago.',marineLife:[{name:'Gorgonian sea fan (forest)',frequency:'very common'},{name:'Pygmy seahorse',frequency:'common'},{name:'Hairy squat lobster',frequency:'common'},{name:'Reef shark',frequency:'common'},{name:'Eagle ray',frequency:'occasional'}],safetyNotes:['Wall dive — watch depth','Gorgonians: do not touch — extremely fragile'],briefing:'Back-roll entry. Descend on wall covered in gorgonian fans. Inspect every fan for pygmy seahorses. Hairy squat lobsters on barrel sponges. Watch blue for sharks. Drift along wall face. SMB pickup.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'wall' },

  { slug:'maratua-channel',name:'The Channel',area:'Maratua Atoll',areaSlug:'maratua-atoll',rank:18,type:'Reef',access:'Boat',minDepth:10,maxDepth:30,avgDepth:20,visibility:'20–40m',temp:'27–30°C',current:'Moderate to strong',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Year-round; slack or incoming tide',bestSeason:'Year-round',goodFor:['Drift diving','Pelagics','Big fish','Schools of fish'],facilities:['Nabucco Island Resort','Maratua Paradise Resort'],lat:2.195,lng:118.600,rating:4.7,reviews:98,description:'The channel entrance into Maratua\'s massive lagoon creates the perfect funnel for marine life. Currents concentrate fish life at the channel mouth — schooling bumphead parrotfish, dogtooth tuna, Napoleon wrasse, jackfish. Maratua\'s ultra-clear water gives dramatic visibility on everything passing through. Resident hawksbill and green turtles. Exhilarating drift when current is running. Nabucco Island Resort is located inside the lagoon, giving exclusive access to The Pass — some of the best pelagic action in the archipelago.',marineLife:[{name:'Bumphead parrotfish',frequency:'common'},{name:'Dogtooth tuna',frequency:'common'},{name:'Napoleon wrasse',frequency:'common'},{name:'Schooling jackfish',frequency:'very common'},{name:'Hawksbill turtle',frequency:'common'}],safetyNotes:['Channel currents — drift dive, no fighting current','Incoming tide for best fish concentration','Exit plan before entering — current can accelerate unexpectedly'],briefing:'Back-roll at channel mouth. Drift with incoming tide for maximum fish action. Bumphead parrotfish and tuna in the blue. Turtles on reef edges. Exit on reef edge — SMB for pickup in calm water.',emergencyContact:'Berau General Hospital: +62 554 21118',diagramType:'drift' },
]

export function getBorneoSiteBySlug(slug:string){ return BORNEO_SITES.find(s=>s.slug===slug) }

